-- {"operators": "INNER_JOIN,AGGREGATE,ORDER,WINDOW,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "DISTRICT,ORDER_LINE", "ducklake": true}
WITH district_rev AS (SELECT ol.OL_W_ID, ol.OL_D_ID, SUM(ol.OL_AMOUNT) AS rev FROM dl.ORDER_LINE ol GROUP BY ol.OL_W_ID, ol.OL_D_ID) SELECT d.D_W_ID, d.D_ID, d.D_NAME, dr.rev, DENSE_RANK() OVER (PARTITION BY d.D_W_ID ORDER BY dr.rev DESC) AS rk FROM dl.DISTRICT d JOIN district_rev dr ON d.D_W_ID = dr.OL_W_ID AND d.D_ID = dr.OL_D_ID;
